  // either `<name>` (resolved against OKG_DEPLOYMENTS_DIR) or an
  // absolute path; the latter avoids the awkward
  // `<repo>/cooper/cooper/deployment.yaml` collision that would
  // result from setting OKG_DEPLOYMENTS_DIR=<repo>/cooper.
  //
  // Defensively strip PZ_OKG_DEPLOYMENT from the inherited
  // environment so a stale export from a previously-sourced
  // .cooper/env (older cooper versions set it to "cooper") cannot
  // race the explicit --deployment arg below. The explicit flag
  // wins anyway in current okg, but clearing the env var keeps the
  // contract obvious.
  const childEnv = { ...process.env, ...env };
  delete childEnv.PZ_OKG_DEPLOYMENT;
  const r = spawnSync(okg, ['ingest', '--deployment', deploymentDir, ...args], {
    stdio: 'inherit',
    env: childEnv,
  });
  if (r.status !== 0) {
    // Common failure: DSN unreachable. Translate to a friendlier
    // hint without swallowing the error.
    if ((r.stderr || '').toString().includes('connection')) {
      console.error('hint: is the database running? `cooper db up` (or check $COOPER_DSN)');
    }
    process.exit(r.status || 1);
  }
  // Drop a tiny status crumb so the scaffold (and humans) can see
  // when the last successful publish ran without shelling out to
  // okg. Keeps the file under cooper/state/ so it sits alongside
  // any other state surfaces a future change might add.
  try {
    writeLastIngestSummary(repoRoot, deploymentDir, env.OKG_DSN);
  } catch (e) {
    // Non-fatal — the publish already succeeded.
    console.error(`warning: couldn't write last_ingest.json: ${e.message}`);
  }
}

function writeLastIngestSummary(repoRoot, deploymentDir, dsn) {
  const stateDir = path.join(repoRoot, 'cooper', 'state');
  fs.mkdirSync(stateDir, { recursive: true });
  // Redact the password from the DSN when persisting; users may
  // have COOPER_DSN set with credentials in URL form.
  const safeDsn = dsn.replace(/:[^:@/]+@/, ':***@');
  const summary = {
    when: new Date().toISOString(),
    deployment: deploymentDir,
    dsn: safeDsn,
    runner: 'cooper ingest',
    cooper_version: loadCooperPackage().version,
  };
  fs.writeFileSync(
    path.join(stateDir, 'last_ingest.json'),
    JSON.stringify(summary, null, 2) + '\n',
    'utf8'
  );
}

function main() {
  const args = process.argv.slice(2);
  const command = args[0];

  if (!command || command === '-h' || command === '--help') {
    printHelp();
    process.exit(0);
  }

  try {
    if (command === 'init') {
      runInit(args.slice(1));
      return;
    }

    if (command === 'update') {
      runUpdate(args.slice(1));
      return;
    }

    if (command === 'db') {
      runDb(args.slice(1));
      return;
    }

    if (command === 'engine') {
      runEngine(args.slice(1));
      return;
    }

    if (command === 'ingest') {
      runIngest(args.slice(1));
      return;
    }

    throw new Error(`Unknown command: ${command}`);
  } catch (error) {
    console.error(`Error: ${error.message}`);
    process.exit(1);
  }
}

