// Shared helpers for the `cooper hook <event>` subcommand.
//
// All hook handlers read a Claude Code hook payload from stdin
// (JSON), perform their check against the cooper scaffold, and
// emit a hook output (JSON to stdout, or exit 2 for blocking).
//
// This module deliberately avoids any external dependency — cooper
// has none today, and a hook needs to be cheap to spawn. The
// frontmatter parser only understands the YAML subset cooper uses
// in runlog.md and brief.md (scalars, simple lists, nested objects
// of scalars). It is not a general YAML parser.

const fs = require('fs');
const path = require('path');

// ---------------------------------------------------------------------------
// Path / discovery
// ---------------------------------------------------------------------------

// Walk up from `start` until a directory containing `cooper/AGENTS.md`
// is found. Returns the **repo root** (parent of `cooper/`) or null.
function findRepoRoot(start) {
  let dir = path.resolve(start);
  while (true) {
    if (fs.existsSync(path.join(dir, 'cooper', 'AGENTS.md'))) return dir;
    const parent = path.dirname(dir);
    if (parent === dir) return null;
    dir = parent;
  }
}

// Convenience accessors for the cooper layout under a repo root.
function cooperPaths(repoRoot) {
  const cooperDir = path.join(repoRoot, 'cooper');
  return {
    repoRoot,
    cooperDir,
    studiesDir: path.join(cooperDir, 'studies'),
    stateDir: path.join(cooperDir, '.cooper'),
    sessionStatePath: path.join(cooperDir, '.cooper', 'session_state.json'),
  };
}

// ---------------------------------------------------------------------------
// Today / dates
// ---------------------------------------------------------------------------

function todayIso() {
  const d = new Date();
  const yyyy = d.getFullYear();
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const dd = String(d.getDate()).padStart(2, '0');
  return `${yyyy}-${mm}-${dd}`;
}

// ---------------------------------------------------------------------------
// Frontmatter parser (cooper-flavored YAML subset)
// ---------------------------------------------------------------------------
//
// Supports:
//   key: scalar              (string / number / bool / null)
//   key: "quoted scalar"
//   key: [a, b, c]           (inline list of scalars)
//   key:
//     - item                 (block list of scalars)
//     - item
//   key:                     (block list of mappings is NOT supported)
//
// Comments (# ...) and blank lines are ignored.
// Indentation must be two spaces for block lists.
//
// Returns { frontmatter: object, body: string, hadFrontmatter: bool }.

function splitFrontmatter(text) {
  if (!text.startsWith('---\n') && !text.startsWith('---\r\n')) {
    return { frontmatter: {}, body: text, hadFrontmatter: false };
  }
  const sep = text.indexOf('\n---', 4);
  if (sep === -1) return { frontmatter: {}, body: text, hadFrontmatter: false };
  const fmText = text.slice(4, sep);
  // Body starts after the closing --- and its trailing newline.
  const afterClose = text.indexOf('\n', sep + 4);
  const body = afterClose === -1 ? '' : text.slice(afterClose + 1);
  return { frontmatter: parseFrontmatter(fmText), body, hadFrontmatter: true };
}

function parseFrontmatter(text) {
  const out = {};
  const lines = text.split(/\r?\n/);
  let i = 0;
  while (i < lines.length) {
    const raw = lines[i];
    if (!raw.trim() || raw.trim().startsWith('#')) {
      i += 1;
      continue;
    }
    // Top-level key.
    const m = raw.match(/^([A-Za-z_][\w-]*)\s*:\s*(.*)$/);
    if (!m) {
      i += 1;
      continue;
    }
    const key = m[1];
    const rest = m[2].trim();
    if (rest === '') {
      // Block list candidate.
      const items = [];
      i += 1;
      while (i < lines.length) {
        const peek = lines[i];
        if (!peek.trim() || peek.trim().startsWith('#')) {
          i += 1;
          continue;
        }
        const bm = peek.match(/^\s+-\s+(.*)$/);
        if (!bm) break;
        items.push(parseScalar(bm[1].trim()));
        i += 1;
      }
      out[key] = items;
      continue;
    }
    if (rest.startsWith('[') && rest.endsWith(']')) {
      // Inline list.
      const inner = rest.slice(1, -1).trim();
      out[key] = inner === '' ? [] : inner.split(',').map((s) => parseScalar(s.trim()));
      i += 1;
      continue;
    }
    out[key] = parseScalar(rest);
    i += 1;
  }
  return out;
}

function parseScalar(s) {
  if (s === '' || s === 'null' || s === '~') return null;
  if (s === 'true') return true;
  if (s === 'false') return false;
  if (/^-?\d+$/.test(s)) return parseInt(s, 10);
  if (/^-?\d*\.\d+$/.test(s)) return parseFloat(s);
  if ((s.startsWith('"') && s.endsWith('"')) || (s.startsWith("'") && s.endsWith("'"))) {
    return s.slice(1, -1);
  }
  return s;
}

// Serialize a frontmatter object back to YAML. Round-trips the
// subset we parse. Used only to update specific keys in place.
function stringifyFrontmatter(obj) {
  const lines = [];
  for (const [k, v] of Object.entries(obj)) {
    if (v === null || v === undefined) {
      lines.push(`${k}: null`);
    } else if (Array.isArray(v)) {
      if (v.length === 0) {
        lines.push(`${k}: []`);
      } else {
        lines.push(`${k}:`);
        for (const item of v) lines.push(`  - ${formatScalar(item)}`);
      }
    } else if (typeof v === 'object') {
      lines.push(`${k}:`);
      for (const [sk, sv] of Object.entries(v)) {
        lines.push(`  ${sk}: ${formatScalar(sv)}`);
      }
    } else {
      lines.push(`${k}: ${formatScalar(v)}`);
    }
  }
  return lines.join('\n');
}

function formatScalar(v) {
  if (v === null || v === undefined) return 'null';
  if (typeof v === 'boolean') return v ? 'true' : 'false';
  if (typeof v === 'number') return String(v);
  return String(v);
}

// ---------------------------------------------------------------------------
// Study discovery
// ---------------------------------------------------------------------------

function listStudies(paths) {
  if (!fs.existsSync(paths.studiesDir)) return [];
  return fs
    .readdirSync(paths.studiesDir, { withFileTypes: true })
    .filter((e) => e.isDirectory() && e.name !== '_template' && !e.name.startsWith('.'))
    .map((e) => ({
      id: e.name,
      dir: path.join(paths.studiesDir, e.name),
      runlogPath: path.join(paths.studiesDir, e.name, 'runlog.md'),
      briefPath: path.join(paths.studiesDir, e.name, 'brief.md'),
    }))
    .filter((s) => fs.existsSync(s.runlogPath));
}

function readRunlog(runlogPath) {
  if (!fs.existsSync(runlogPath)) return null;
  const text = fs.readFileSync(runlogPath, 'utf8');
  const { frontmatter, body, hadFrontmatter } = splitFrontmatter(text);
  return { path: runlogPath, frontmatter, body, hadFrontmatter, text };
}

function readBrief(briefPath) {
  if (!fs.existsSync(briefPath)) return null;
  const text = fs.readFileSync(briefPath, 'utf8');
  const { frontmatter, body, hadFrontmatter } = splitFrontmatter(text);
  return { path: briefPath, frontmatter, body, hadFrontmatter, text };
}

function runningStudies(paths) {
  return listStudies(paths)
    .map((s) => ({ study: s, runlog: readRunlog(s.runlogPath) }))
    .filter((x) => x.runlog && x.runlog.frontmatter.status === 'running');
}

// ---------------------------------------------------------------------------
// Session state (cooper/.cooper/session_state.json)
// ---------------------------------------------------------------------------

function readSessionState(paths) {
  if (!fs.existsSync(paths.sessionStatePath)) return { sessions: {} };
  try {
    return JSON.parse(fs.readFileSync(paths.sessionStatePath, 'utf8'));
  } catch (_e) {
    return { sessions: {} };
  }
}

function writeSessionState(paths, state) {
  fs.mkdirSync(paths.stateDir, { recursive: true });
  // Ensure .gitignore exists so users do not accidentally commit
  // ephemeral state on first hook write.
  const gitignorePath = path.join(paths.stateDir, '.gitignore');
  if (!fs.existsSync(gitignorePath)) {
    fs.writeFileSync(gitignorePath, '*\n!.gitignore\n', 'utf8');
  }
  fs.writeFileSync(paths.sessionStatePath, JSON.stringify(state, null, 2) + '\n', 'utf8');
}

function getBoundStudyId(paths, sessionId) {
  const state = readSessionState(paths);
  return state.sessions && state.sessions[sessionId] ? state.sessions[sessionId].study_id : null;
}

function bindSession(paths, sessionId, studyId, extra = {}) {
  const state = readSessionState(paths);
  state.sessions = state.sessions || {};
  state.sessions[sessionId] = {
    study_id: studyId,
    bound_at: new Date().toISOString(),
    ...extra,
  };
  writeSessionState(paths, state);
}

// ---------------------------------------------------------------------------
// Per-session work tracking (which tools fired this turn).
// Persisted to .cooper/turn_state.json keyed by session_id; reset
// on each Stop. Used by C7.
// ---------------------------------------------------------------------------

function turnStatePath(paths) {
  return path.join(paths.stateDir, 'turn_state.json');
}

function readTurnState(paths) {
  const p = turnStatePath(paths);
  if (!fs.existsSync(p)) return {};
  try {
    return JSON.parse(fs.readFileSync(p, 'utf8'));
  } catch (_e) {
    return {};
  }
}

function writeTurnState(paths, state) {
  fs.mkdirSync(paths.stateDir, { recursive: true });
  fs.writeFileSync(turnStatePath(paths), JSON.stringify(state, null, 2) + '\n', 'utf8');
}

function recordToolUse(paths, sessionId, toolName, targetPath) {
  const all = readTurnState(paths);
  const turn = all[sessionId] || { tools: [], runlog_edits: [], started: new Date().toISOString() };
  turn.tools.push({ tool: toolName, target: targetPath || null, at: new Date().toISOString() });
  if (targetPath && /(^|\/)studies\/[^/]+\/runlog\.md$/.test(targetPath)) {
    turn.runlog_edits.push(targetPath);
  }
  all[sessionId] = turn;
  writeTurnState(paths, all);
}

function clearTurn(paths, sessionId) {
  const all = readTurnState(paths);
  delete all[sessionId];
  writeTurnState(paths, all);
}

// ---------------------------------------------------------------------------
// Runlog structure validation (C5)
// ---------------------------------------------------------------------------

const REQUIRED_RUNLOG_KEYS = [
  'id',
  'title',
  'status',
  'question',
  'owner',
  'created',
  'updated',
  'preferred_run',
  'tags',
  'parent',
];

const CANONICAL_RUNLOG_SECTIONS = [
  'Guiding Question',
  'Hypotheses',
  'Ideas / Methods Explored',
  'Dead-Ends',
  'Findings',
  'Open Questions',
  'Decisions',
  'Next Action',
];

function validateRunlogStructure(runlog) {
  const errors = [];
  if (!runlog.hadFrontmatter) {
    errors.push('runlog has no YAML frontmatter');
    return errors;
  }
  for (const key of REQUIRED_RUNLOG_KEYS) {
    if (!(key in runlog.frontmatter)) errors.push(`frontmatter missing required key: ${key}`);
  }
  // Extract `## ` headings from body in order.
  const found = [];
  for (const line of runlog.body.split(/\r?\n/)) {
    const m = line.match(/^##\s+(.+?)\s*$/);
    if (m) found.push(m[1].trim());
  }
  for (let i = 0; i < CANONICAL_RUNLOG_SECTIONS.length; i += 1) {
    const expected = CANONICAL_RUNLOG_SECTIONS[i];
    if (found[i] !== expected) {
      errors.push(`expected section ${i + 1} to be "## ${expected}", got "## ${found[i] || '(missing)'}"`);
    }
  }
  return errors;
}

// ---------------------------------------------------------------------------
// Brief staleness (C4) + runlog delta extraction
// ---------------------------------------------------------------------------

function briefStale(runlog, brief) {
  if (!brief) return { stale: true, reason: 'brief.md does not exist' };
  const last = brief.frontmatter.last_synced_runlog_updated;
  const cur = runlog.frontmatter.updated;
  if (!cur) return { stale: false, reason: 'runlog has no updated: yet' };
  if (!last) return { stale: true, reason: 'brief has never been synced' };
  if (String(last) < String(cur)) {
    return { stale: true, reason: `brief synced at ${last}, runlog updated at ${cur}` };
  }
  return { stale: false, reason: 'brief is up to date' };
}

// Pull section bodies from runlog text so a hook can hand the agent
// the delta payload it needs to refresh brief.md.
function extractRunlogSections(runlog) {
  const sections = {};
  if (!runlog) return sections;
  let current = null;
  let buf = [];
  for (const line of runlog.body.split(/\r?\n/)) {
    const m = line.match(/^##\s+(.+?)\s*$/);
    if (m) {
      if (current !== null) sections[current] = buf.join('\n').trim();
      current = m[1].trim();
      buf = [];
    } else if (current !== null) {
      buf.push(line);
    }
  }
  if (current !== null) sections[current] = buf.join('\n').trim();
  return sections;
}

// ---------------------------------------------------------------------------
// Hook I/O
// ---------------------------------------------------------------------------

function readHookInput() {
  // Hooks receive the payload on stdin. Read synchronously so the
  // handler can stay simple. If stdin is empty (e.g. invoked
  // manually), return an empty object so the handler degrades to a
  // no-op rather than crashing.
  try {
    const data = fs.readFileSync(0, 'utf8');
    if (!data.trim()) return {};
    return JSON.parse(data);
  } catch (_e) {
    return {};
  }
}

function emitJson(obj) {
  process.stdout.write(JSON.stringify(obj));
}

function emitContext(context, extra = {}) {
  emitJson({
    continue: true,
    hookSpecificOutput: {
      hookEventName: extra.eventName,
      additionalContext: context,
      ...extra.hookSpecific,
    },
    ...extra.top,
  });
}

function emitBlock(reason) {
  emitJson({ decision: 'block', reason });
}

function emitDenyPreToolUse(reason) {
  emitJson({
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      permissionDecision: 'deny',
      permissionDecisionReason: reason,
    },
  });
}

function emitContextPreToolUse(context) {
  emitJson({
    hookSpecificOutput: {
      hookEventName: 'PreToolUse',
      additionalContext: context,
    },
  });
}

// ---------------------------------------------------------------------------
// Resolver: turn hook input into a working context for handlers.
// ---------------------------------------------------------------------------

function resolveContext(input) {
  const cwd = input.cwd || process.cwd();
  const repoRoot = findRepoRoot(cwd);
  if (!repoRoot) return { input, cwd, repoRoot: null, paths: null };
  const paths = cooperPaths(repoRoot);
  return { input, cwd, repoRoot, paths };
}

module.exports = {
  findRepoRoot,
  cooperPaths,
  todayIso,
  splitFrontmatter,
  parseFrontmatter,
  stringifyFrontmatter,
  listStudies,
  readRunlog,
  readBrief,
  runningStudies,
  readSessionState,
  writeSessionState,
  getBoundStudyId,
  bindSession,
  readTurnState,
  writeTurnState,
  recordToolUse,
  clearTurn,
  validateRunlogStructure,
  briefStale,
  extractRunlogSections,
  readHookInput,
  emitJson,
  emitContext,
  emitBlock,
  emitDenyPreToolUse,
  emitContextPreToolUse,
  resolveContext,
  REQUIRED_RUNLOG_KEYS,
  CANONICAL_RUNLOG_SECTIONS,
};

