// SessionStart hook: implements C1b (inject active-study context)
// and establishes the session<->study binding.
//
// Resolution rules (see CONTRACT.md):
//   - If session_state.json already has an entry for this session_id,
//     use it (resumed session).
//   - Else list studies with `status: running`:
//       1 -> bind automatically
//       0 -> leave unbound; C2 will force the agent to create a study
//      >1 -> emit a notice listing candidates; require the agent to
//             pick by writing to session_state.json before C2 will
//             pass.

const fs = require('fs');
const lib = require('./lib');

const input = lib.readHookInput();
const ctx = lib.resolveContext(input);

if (!ctx.paths) {
  // Not in a cooper repo — nothing to do.
  lib.emitJson({ continue: true });
  process.exit(0);
}

const sessionId = input.session_id || 'unknown-session';
let boundStudyId = lib.getBoundStudyId(ctx.paths, sessionId);

if (!boundStudyId) {
  const running = lib.runningStudies(ctx.paths);
  if (running.length === 1) {
    boundStudyId = running[0].study.id;
    lib.bindSession(ctx.paths, sessionId, boundStudyId);
  } else if (running.length > 1) {
    const list = running.map((r) => `  - ${r.study.id}`).join('\n');
    const ctxText =
      `[cooper] Multiple studies have status: running. ` +
      `Pick one for this session by writing\n` +
      `  { "sessions": { "${sessionId}": { "study_id": "<chosen>" } } }\n` +
      `into cooper/.cooper/session_state.json (or run the binding helper).\n` +
      `Candidates:\n${list}`;
    lib.emitContext(ctxText, { eventName: 'SessionStart' });
    process.exit(0);
  }
  // running.length === 0: leave unbound. C2 will gate substantive work.
}

const pieces = [];
pieces.push('[cooper] session bootstrap');

if (!boundStudyId) {
  pieces.push(
    'No active study. Before any Edit/Write/Bash, copy cooper/studies/_template/ to ' +
      'cooper/studies/<short-slug>/, set status: running in the runlog frontmatter, ' +
      'and write a Hypothesis (per AGENTS.md "Required Workflow"). The binding will ' +
      'be set automatically when the new runlog is created.'
  );
  lib.emitContext(pieces.join('\n\n'), { eventName: 'SessionStart' });
  process.exit(0);
}

// We have a bound study — inject its state.
const study = lib.listStudies(ctx.paths).find((s) => s.id === boundStudyId);
if (!study) {
  pieces.push(
    `[cooper] WARNING: session is bound to study "${boundStudyId}" but that study folder does not exist. ` +
      `Either restore it or unbind by deleting the entry from cooper/.cooper/session_state.json.`
  );
  lib.emitContext(pieces.join('\n\n'), { eventName: 'SessionStart' });
  process.exit(0);
}

const runlog = lib.readRunlog(study.runlogPath);
const brief = lib.readBrief(study.briefPath);

pieces.push(`Active study: ${boundStudyId}`);
pieces.push(`Runlog: ${path.relative(ctx.repoRoot, study.runlogPath)}`);
if (brief) pieces.push(`Brief: ${path.relative(ctx.repoRoot, study.briefPath)}`);

if (runlog) {
  pieces.push('--- runlog.md ---\n' + runlog.text.trim());
}
if (brief) {
  const stale = lib.briefStale(runlog, brief);
  pieces.push('--- brief.md ---\n' + brief.text.trim());
  if (stale.stale) {
    pieces.push(`[cooper] brief.md is STALE (${stale.reason}). Refresh it via the study-brief skill before ending the session.`);
  }
}

const path = require('path');
lib.emitContext(pieces.join('\n\n'), { eventName: 'SessionStart' });

