// PostToolUse hook:
//   - Records this turn's tool use (for C7 at Stop).
//   - If a new runlog with status: running was just created, set the
//     session<->study binding automatically (C2 carve-out completion).
//   - For Edit/Write on **/runlog.md, warn on:
//       C3 — runlog updated: != today
//       C4 — brief.md is stale relative to runlog.md
//       C5 — runlog structure invalid

const path = require('path');
const lib = require('./lib');

const input = lib.readHookInput();
const ctx = lib.resolveContext(input);

if (!ctx.paths) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

const tool = input.tool_name || '';
const toolInput = input.tool_input || {};
const sessionId = input.session_id || 'unknown-session';
const targetPath = toolInput.file_path || toolInput.path || '';

lib.recordToolUse(ctx.paths, sessionId, tool, targetPath);

// Only the editing tools trigger checks below.
if (!['Edit', 'Write', 'MultiEdit', 'NotebookEdit'].includes(tool)) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

// Resolve absolute path for matching.
const absTarget = path.isAbsolute(targetPath) ? targetPath : path.resolve(ctx.cwd, targetPath);

// Is this a runlog edit?
const runlogMatch = absTarget.match(/(^|\/)cooper\/studies\/([^/]+)\/runlog\.md$/);
if (!runlogMatch) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

const studyId = runlogMatch[2];
const studyDir = path.join(ctx.paths.studiesDir, studyId);
const runlogPath = path.join(studyDir, 'runlog.md');
const briefPath = path.join(studyDir, 'brief.md');
const runlog = lib.readRunlog(runlogPath);
const brief = lib.readBrief(briefPath);

// Binding side-effect: if this runlog is status: running and the
// session isn't bound to any study, bind it now.
if (runlog && runlog.frontmatter.status === 'running' && !lib.getBoundStudyId(ctx.paths, sessionId)) {
  lib.bindSession(ctx.paths, sessionId, studyId, { reason: 'auto-bound on study creation' });
}

const warnings = [];

// C5 — structure (run first, then C3/C4 only if structure is valid enough).
if (runlog) {
  const errors = lib.validateRunlogStructure(runlog);
  if (errors.length > 0) {
    warnings.push(`[cooper C5] runlog structure invalid:\n  - ${errors.join('\n  - ')}`);
  }

  // C3 — updated: == today
  const updated = runlog.frontmatter.updated;
  const today = lib.todayIso();
  if (updated !== today) {
    warnings.push(
      `[cooper C3] runlog updated: is "${updated || 'null'}"; bump to "${today}" since the runlog was edited today.`
    );
  }

  // C4 — brief catches up
  const stale = lib.briefStale(runlog, brief);
  if (stale.stale) {
    const delta = brief
      ? `Sections to incorporate from the runlog (compare against brief.last_synced_runlog_updated=${brief.frontmatter.last_synced_runlog_updated || 'null'}):`
      : 'brief.md does not yet exist. Create it from cooper/studies/_template/brief.md and fill the auto sections from the runlog:';
    const sections = lib.extractRunlogSections(runlog);
    const interesting = ['Findings', 'Decisions', 'Hypotheses', 'Dead-Ends', 'Open Questions'];
    const payload = interesting
      .map((name) => (sections[name] ? `### ${name}\n${sections[name]}` : null))
      .filter(Boolean)
      .join('\n\n');
    warnings.push(
      `[cooper C4] brief.md is STALE (${stale.reason}).\n${delta}\n\n${payload}`
    );
  }
}

if (warnings.length === 0) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

lib.emitJson({
  continue: true,
  hookSpecificOutput: {
    hookEventName: 'PostToolUse',
    additionalContext: warnings.join('\n\n'),
  },
});

