// Stop hook: end-of-turn enforcement.
//
//   C3 — runlog updated: must == today (if the runlog changed this turn)
//   C4 — brief.md must catch up
//   C5 — runlog must be structurally valid
//   C7 — if the turn did any Edit|Write|Bash, the runlog must have been touched
//
// Any of these failures returns {decision: "block", reason: ...} so
// Claude must re-attempt. Once they all pass, the turn's tool-use
// record is cleared so the next turn starts fresh.

const path = require('path');
const lib = require('./lib');

const input = lib.readHookInput();
const ctx = lib.resolveContext(input);

if (!ctx.paths) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

const sessionId = input.session_id || 'unknown-session';
const turns = lib.readTurnState(ctx.paths);
const turn = turns[sessionId] || { tools: [], runlog_edits: [] };
const boundStudyId = lib.getBoundStudyId(ctx.paths, sessionId);

const workTools = turn.tools.filter((t) => ['Edit', 'Write', 'Bash', 'MultiEdit', 'NotebookEdit'].includes(t.tool));
const didWork = workTools.length > 0;

const reasons = [];

if (boundStudyId) {
  const studyDir = path.join(ctx.paths.studiesDir, boundStudyId);
  const runlog = lib.readRunlog(path.join(studyDir, 'runlog.md'));
  const brief = lib.readBrief(path.join(studyDir, 'brief.md'));

  // C7 — runlog must be touched on every working turn.
  if (didWork && turn.runlog_edits.length === 0) {
    reasons.push(
      `[cooper C7] this turn made ${workTools.length} Edit/Write/Bash call(s) but did not touch the active runlog ` +
        `(cooper/studies/${boundStudyId}/runlog.md). ` +
        'Record what happened under ## Findings / ## Decisions / ## Hypotheses, or set status: paused if there is nothing to record.'
    );
  }

  if (runlog) {
    // C5 — structure valid.
    const errors = lib.validateRunlogStructure(runlog);
    if (errors.length > 0) {
      reasons.push(`[cooper C5] runlog structure invalid:\n  - ${errors.join('\n  - ')}`);
    }

    // C3 — updated: == today (only if the runlog was touched this turn).
    if (turn.runlog_edits.length > 0) {
      const today = lib.todayIso();
      if (runlog.frontmatter.updated !== today) {
        reasons.push(
          `[cooper C3] runlog updated: is "${runlog.frontmatter.updated || 'null'}"; bump to "${today}" before ending the session.`
        );
      }
    }

    // C4 — brief catches up (only check if the runlog was touched this turn).
    if (turn.runlog_edits.length > 0) {
      const stale = lib.briefStale(runlog, brief);
      if (stale.stale) {
        reasons.push(
          `[cooper C4] brief.md is stale (${stale.reason}). Refresh it via the study-brief skill before ending the session.`
        );
      }
    }
  }
}

if (reasons.length === 0) {
  // Clean turn — clear state.
  lib.clearTurn(ctx.paths, sessionId);
  lib.emitJson({ continue: true });
  process.exit(0);
}

// Block.
lib.emitBlock(reasons.join('\n\n'));

