// PreCompact hook: re-inject active study state so it survives
// compaction (C6), snapshot the transcript (C6), and surface the
// knowledge-promotion prompt (C8).

const fs = require('fs');
const path = require('path');
const lib = require('./lib');

const input = lib.readHookInput();
const ctx = lib.resolveContext(input);

if (!ctx.paths) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

const sessionId = input.session_id || 'unknown-session';
const boundStudyId = lib.getBoundStudyId(ctx.paths, sessionId);
const transcriptPath = input.transcript_path;

const pieces = [];

// C6 — inject active study state.
if (boundStudyId) {
  const studyDir = path.join(ctx.paths.studiesDir, boundStudyId);
  const runlog = lib.readRunlog(path.join(studyDir, 'runlog.md'));
  const brief = lib.readBrief(path.join(studyDir, 'brief.md'));
  pieces.push(`[cooper C6] Active study: ${boundStudyId} (re-injected pre-compaction)`);
  if (runlog) pieces.push('--- runlog.md ---\n' + runlog.text.trim());
  if (brief) pieces.push('--- brief.md ---\n' + brief.text.trim());

  // C6 — transcript snapshot.
  if (transcriptPath && fs.existsSync(transcriptPath)) {
    try {
      const sessionsDir = path.join(studyDir, 'sessions');
      fs.mkdirSync(sessionsDir, { recursive: true });
      const stamp = new Date().toISOString().replace(/[:.]/g, '-');
      const dst = path.join(sessionsDir, `${sessionId}__precompact_${stamp}.jsonl`);
      fs.copyFileSync(transcriptPath, dst);
      pieces.push(`[cooper C6] transcript snapshot written: ${path.relative(ctx.repoRoot, dst)}`);
    } catch (e) {
      pieces.push(`[cooper C6] WARNING: could not snapshot transcript: ${e.message}`);
    }
  }
}

// C8 — knowledge promotion prompt.
