// SessionEnd hook: copy the transcript into the study's sessions/
// directory (C6) and surface the knowledge-promotion prompt (C8).
//
// This hook fires after the agent has stopped, so it cannot block.
// It logs to stderr (which the harness surfaces) if anything goes
// wrong.

const fs = require('fs');
const path = require('path');
const lib = require('./lib');

const input = lib.readHookInput();
const ctx = lib.resolveContext(input);

if (!ctx.paths) {
  lib.emitJson({ continue: true });
  process.exit(0);
}

const sessionId = input.session_id || 'unknown-session';
const boundStudyId = lib.getBoundStudyId(ctx.paths, sessionId);
const transcriptPath = input.transcript_path;

if (boundStudyId && transcriptPath && fs.existsSync(transcriptPath)) {
  try {
    const studyDir = path.join(ctx.paths.studiesDir, boundStudyId);
    const sessionsDir = path.join(studyDir, 'sessions');
    fs.mkdirSync(sessionsDir, { recursive: true });
    const dst = path.join(sessionsDir, `${sessionId}.jsonl`);
    fs.copyFileSync(transcriptPath, dst);
    process.stderr.write(`[cooper C6] transcript copied to ${path.relative(ctx.repoRoot, dst)}\n`);
  } catch (e) {
    process.stderr.write(`[cooper C6] WARNING: could not copy transcript: ${e.message}\n`);
  }
}

// C8 prompt as a stderr breadcrumb (no agent to receive it post-stop).
process.stderr.write(
  '[cooper C8] Session ending. If anything reusable was learned, promote it into ' +
    'cooper/knowledge/ or cooper/skills/ in the next session.\n'
);

// Clean up turn_state for this session.
lib.clearTurn(ctx.paths, sessionId);

lib.emitJson({ continue: true });

