function copyDir(srcDir, dstDir, force, stats) {
  fs.mkdirSync(dstDir, { recursive: true });
  const entries = fs.readdirSync(srcDir, { withFileTypes: true });

  for (const entry of entries) {
    const src = path.join(srcDir, entry.name);
    const dst = path.join(dstDir, entry.name);

    if (entry.isDirectory()) {
      copyDir(src, dst, force, stats);
      continue;
    }

    if (fs.existsSync(dst) && !force) {
      stats.skipped += 1;
      continue;
    }

    fs.mkdirSync(path.dirname(dst), { recursive: true });
    fs.copyFileSync(src, dst);
    stats.written += 1;
  }
}

function upsertManagedBlock(repoRoot, subdir) {
  const agentsPath = path.join(repoRoot, 'AGENTS.md');
  const block = [
    BLOCK_START,
    '# Cooper Instructions',
    '',
    'These instructions are for AI assistants working in this repository.',
    '',
    `Always open \`@/${subdir}/AGENTS.md\` before implementation work.`,
    '',
    `Use \`@/${subdir}/AGENTS.md\` to follow Cooper workflow, study, knowledge, and skill conventions.`,
    '',
    `The OKG ingestion config lives in \`@/${subdir}/deployment/\`. Run \`cooper db up && cooper engine install && cooper ingest\` to publish a graph generation over your scaffold.`,
    '',
    'Keep this managed block so future `cooper init` and `cooper update` runs can refresh it.',
    '',
    BLOCK_END,
  ].join('\n');

  let body = '';
  if (fs.existsSync(agentsPath)) {
    body = fs.readFileSync(agentsPath, 'utf8');
    const start = body.indexOf(BLOCK_START);
    const end = body.indexOf(BLOCK_END);

    if (start !== -1 && end !== -1 && end > start) {
      const afterEnd = end + BLOCK_END.length;
      const before = body.slice(0, start).trimEnd();
      const after = body.slice(afterEnd).trimStart();
      const merged = [before, block, after].filter(Boolean).join('\n\n');
      fs.writeFileSync(agentsPath, `${merged}\n`, 'utf8');
      return;
    }

    fs.writeFileSync(agentsPath, `${block}\n\n${body}`, 'utf8');
    return;
  }

  fs.writeFileSync(agentsPath, `${block}\n`, 'utf8');
}

function cleanupLegacyGitignore(repoRoot, subdir) {
  const gitignorePath = path.join(repoRoot, '.gitignore');
