#!/usr/bin/env node
//
// Hook unit tests. Each test builds a tiny fake cooper scaffold in
// a tmp dir, runs `cooper hook <event>` with a synthetic payload on
// stdin, and asserts on the JSON output.

const assert = require('node:assert');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');
const { spawnSync } = require('node:child_process');

const repoRoot = path.resolve(__dirname, '..');
const binPath = path.join(repoRoot, 'bin', 'cooper.js');

let passed = 0;
let failed = 0;

function test(name, fn) {
  try {
    fn();
    console.log(`  ✓ ${name}`);
    passed += 1;
  } catch (e) {
    console.log(`  ✗ ${name}`);
    console.log(`    ${e.message}`);
    if (e.stack) console.log(e.stack.split('\n').slice(1, 4).join('\n'));
    failed += 1;
  }
}

function mkTmp() {
  return fs.mkdtempSync(path.join(os.tmpdir(), 'cooper-hooks-'));
}

function writeRunlog(filepath, opts = {}) {
  const today = new Date().toISOString().slice(0, 10);
  const fm = {
    id: opts.id || 'study_test',
    title: opts.title || 'Test',
    status: opts.status || 'running',
    question: opts.question || 'A test question',
    owner: opts.owner || 'test',
    created: opts.created || today,
    updated: opts.updated || today,
    preferred_run: 'null',
    tags: '[]',
    parent: 'null',
  };
  const fmLines = Object.entries(fm)
    .map(([k, v]) => `${k}: ${v}`)
    .join('\n');
  const body =
    opts.body ||
    [
      '## Guiding Question',
      '',
      'tbd.',
      '',
      '## Hypotheses',
      '- placeholder [active]',
      '',
      '## Ideas / Methods Explored',
      '- placeholder',
      '',
      '## Dead-Ends',
      '- none',
      '',
      '## Findings',
      '- none',
      '',
      '## Open Questions',
      '- placeholder',
      '',
      '## Decisions',
      '- none',
      '',
      '## Next Action',
      '',
      'tbd.',
      '',
    ].join('\n');
  fs.mkdirSync(path.dirname(filepath), { recursive: true });
  fs.writeFileSync(filepath, `---\n${fmLines}\n---\n\n${body}`, 'utf8');
}

function writeBrief(filepath, opts = {}) {
  const fm = [
    `study_id: ${opts.study_id || 'study_test'}`,
    `last_synced_runlog_updated: ${opts.last_synced_runlog_updated || 'null'}`,
    `last_synced_at: ${opts.last_synced_at || 'null'}`,
    'auto_sections:',
    '  - TL;DR',
    'manual_sections: []',
  ].join('\n');
  fs.mkdirSync(path.dirname(filepath), { recursive: true });
  fs.writeFileSync(filepath, `---\n${fm}\n---\n\n## TL;DR\n\ntbd.\n`, 'utf8');
}

function buildFakeRepo() {
  const root = mkTmp();
  fs.mkdirSync(path.join(root, 'cooper'), { recursive: true });
  fs.writeFileSync(path.join(root, 'cooper', 'AGENTS.md'), '# Fake AGENTS.md\n', 'utf8');
  fs.mkdirSync(path.join(root, 'cooper', 'studies'), { recursive: true });
  return root;
}

function runHook(event, payload) {
  const r = spawnSync('node', [binPath, 'hook', event], {
    input: JSON.stringify(payload),
    encoding: 'utf8',
  });
  let parsed = null;
  try {
    parsed = r.stdout ? JSON.parse(r.stdout) : null;
  } catch (_e) {
    // leave parsed = null; tests can check raw output instead
  }
  return { status: r.status, stdout: r.stdout, stderr: r.stderr, parsed };
}

// ---------------------------------------------------------------------------
// SessionStart
// ---------------------------------------------------------------------------

console.log('SessionStart');

test('no running studies -> directs agent to create one', () => {
  const root = buildFakeRepo();
  const r = runHook('session-start', { session_id: 's1', cwd: root });
  assert.strictEqual(r.status, 0);
  assert.ok(r.parsed);
  const ctx = r.parsed.hookSpecificOutput.additionalContext;
  assert.match(ctx, /No active study/);
  assert.match(ctx, /copy cooper\/studies\/_template\//);
});

test('exactly one running study -> binds and injects', () => {
  const root = buildFakeRepo();
  writeRunlog(path.join(root, 'cooper', 'studies', 'study_test', 'runlog.md'));
  writeBrief(path.join(root, 'cooper', 'studies', 'study_test', 'brief.md'));
  const r = runHook('session-start', { session_id: 's1', cwd: root });
  assert.strictEqual(r.status, 0);
  const ctx = r.parsed.hookSpecificOutput.additionalContext;
  assert.match(ctx, /Active study: study_test/);
  assert.match(ctx, /--- runlog\.md ---/);
  assert.match(ctx, /--- brief\.md ---/);
  // Binding written.
  const state = JSON.parse(
    fs.readFileSync(path.join(root, 'cooper', '.cooper', 'session_state.json'), 'utf8')
  );
  assert.strictEqual(state.sessions.s1.study_id, 'study_test');
});

test('multiple running studies -> requests agent picks', () => {
  const root = buildFakeRepo();
  writeRunlog(path.join(root, 'cooper', 'studies', 'a', 'runlog.md'), { id: 'a' });
  writeRunlog(path.join(root, 'cooper', 'studies', 'b', 'runlog.md'), { id: 'b' });
  const r = runHook('session-start', { session_id: 's1', cwd: root });
  const ctx = r.parsed.hookSpecificOutput.additionalContext;
  assert.match(ctx, /Multiple studies have status: running/);
  assert.match(ctx, / - a/);
  assert.match(ctx, / - b/);
});

// ---------------------------------------------------------------------------
// PreToolUse (C2)
// ---------------------------------------------------------------------------

console.log('PreToolUse');

test('no binding + Edit -> deny', () => {
  const root = buildFakeRepo();
  const r = runHook('pre-tool-use', {
    session_id: 's1',
    cwd: root,
    tool_name: 'Edit',
    tool_input: { file_path: path.join(root, 'foo.txt') },
  });
  assert.strictEqual(r.parsed.hookSpecificOutput.permissionDecision, 'deny');
  assert.match(r.parsed.hookSpecificOutput.permissionDecisionReason, /no active study/);
});

test('no binding + Write to studies/<x>/runlog.md -> allow (bootstrap carve-out)', () => {
  const root = buildFakeRepo();
  const target = path.join(root, 'cooper', 'studies', 'new_study', 'runlog.md');
  const r = runHook('pre-tool-use', {
    session_id: 's1',
    cwd: root,
    tool_name: 'Write',
    tool_input: { file_path: target },
  });
  assert.strictEqual(r.parsed.continue, true);
  assert.ok(!r.parsed.hookSpecificOutput);
});

test('Read is never gated', () => {
  const root = buildFakeRepo();
  const r = runHook('pre-tool-use', {
    session_id: 's1',
    cwd: root,
