  const r = runHook('pre-tool-use', {
    session_id: 's1',
    cwd: root,
    tool_name: 'Edit',
    tool_input: { file_path: path.join(root, 'foo.txt') },
  });
  assert.strictEqual(r.parsed.continue, true);
});

// ---------------------------------------------------------------------------
// PostToolUse (C3/C4/C5 warn, binding side-effect)
// ---------------------------------------------------------------------------

console.log('PostToolUse');

test('runlog edit with bad date -> warn (C3)', () => {
  const root = buildFakeRepo();
