#!/usr/bin/env node
//
// Smoke test for the `cooper init` → `cooper engine install` →
// `cooper ingest` user flow. Runs in a tmp dir so it doesn't touch
// the dev repo state.
//
// What this verifies:
//   1. `cooper init` produces the expected file shape (scaffold +
//      deployment + study template) and does NOT ship the dev-only
//      sample fixtures.
//   2. The shipped source_registry.yaml has the right user-shape
//      paths (no `templates/cooper/...` prefixes; `${repo_root}` is
//      used).
//   3. `cooper engine status` reports MISSING for engine + env
//      before installing.
//   4. `cooper ingest` exits non-zero with a single-line hint when
//      the engine isn't installed.
//   5. The drift checker (`scripts/check-deployment-template.js`)
//      passes against the worktree.
//
// Out of scope:
//   - Spinning up Postgres or running a full ingest. Those need a
//     fresh DB and SSH access to the engine repo; track that as the
//     CI follow-up referenced in tasks.md Phase 7.1.

'use strict';

const assert = require('assert');
const fs = require('fs');
const os = require('os');
const path = require('path');
const { spawnSync } = require('child_process');

const REPO_ROOT = path.resolve(__dirname, '..');
const COOPER_BIN = path.join(REPO_ROOT, 'bin', 'cooper.js');

let passed = 0;
let failed = 0;

function check(name, fn) {
  try {
    fn();
    console.log(`  ✓ ${name}`);
    passed += 1;
  } catch (err) {
    console.error(`  ✗ ${name}`);
    console.error(`    ${err.message}`);
    failed += 1;
  }
}

function run(cmd, args, opts = {}) {
  return spawnSync(cmd, args, {
    encoding: 'utf8',
    ...opts,
  });
}

function main() {
  const tmpRoot = fs.mkdtempSync(path.join(os.tmpdir(), 'cooper-smoke-'));
  console.log(`tmp dir: ${tmpRoot}\n`);

  console.log('1. cooper init');
  const initR = run('node', [COOPER_BIN, 'init'], { cwd: tmpRoot });
  check('init exits 0', () => assert.strictEqual(initR.status, 0, initR.stderr));

  const cooperDir = path.join(tmpRoot, 'cooper');
  const deploymentDir = path.join(cooperDir, 'deployment');

  check('cooper/AGENTS.md exists', () => assert.ok(fs.existsSync(path.join(cooperDir, 'AGENTS.md'))));
  check('cooper/CONTRACT.md ships', () => assert.ok(fs.existsSync(path.join(cooperDir, 'CONTRACT.md'))));
  check('cooper/deployment/deployment.yaml exists', () =>
    assert.ok(fs.existsSync(path.join(deploymentDir, 'deployment.yaml')))
  );
  check('cooper/deployment/source_registry.yaml exists', () =>
    assert.ok(fs.existsSync(path.join(deploymentDir, 'source_registry.yaml')))
  );
  check('cooper/studies/_template/runlog.md ships', () =>
    assert.ok(fs.existsSync(path.join(cooperDir, 'studies', '_template', 'runlog.md')))
  );
  check('cooper/studies/_template/brief.md ships', () =>
    assert.ok(fs.existsSync(path.join(cooperDir, 'studies', '_template', 'brief.md')))
  );
  check('cooper/skills/study-brief/SKILL.md ships', () =>
    assert.ok(fs.existsSync(path.join(cooperDir, 'skills', 'study-brief', 'SKILL.md')))
  );
  check('dev-only sample AN does not ship', () =>
    assert.ok(!fs.existsSync(path.join(cooperDir, 'refs', 'sample_notes')))
  );
  check('dev-only sample study does not ship', () =>
    assert.ok(!fs.existsSync(path.join(cooperDir, 'studies', 'study_001_abcd_closure_validation')))
  );
  check('dev-only sample slides do not ship', () =>
    assert.ok(!fs.existsSync(path.join(cooperDir, 'working', 'slides', 'talk-2026.tex')))
  );
  check('dev-only sample paper does not ship', () =>
    assert.ok(!fs.existsSync(path.join(cooperDir, 'working', 'paper', 'draft.tex')))
  );
  check('cooper/deployment/tier1/artifacts.py ships', () =>
    assert.ok(fs.existsSync(path.join(deploymentDir, 'tier1', 'artifacts.py')))
  );
  check('cooper/deployment/aliases ships seed YAMLs', () => {
    const yamls = fs
      .readdirSync(path.join(deploymentDir, 'aliases'))
      .filter((f) => f.endsWith('.yaml'));
    assert.ok(yamls.length >= 30, `expected >= 30 alias YAMLs, got ${yamls.length}`);
  });

  console.log('\n2. source_registry.yaml is user-shape');
  const registry = fs.readFileSync(path.join(deploymentDir, 'source_registry.yaml'), 'utf8');
  check('no templates/cooper/ prefix in shipped registry', () =>
    assert.ok(!/templates\/cooper\//.test(registry), 'shipped registry still references dev paths')
  );
  check('uses ${repo_root}/working/AN', () =>
    assert.ok(/\$\{repo_root\}\/working\/AN/.test(registry))
  );
  check('does not reference refs/sample_notes', () =>
    assert.ok(!/refs\/sample_notes/.test(registry), 'shipped registry still references dev sample fixtures')
  );
  check('uses ${repo_root}/studies', () =>
    assert.ok(/\$\{repo_root\}\/studies/.test(registry))
  );
  check('uses ${repo_root}/deployment/aliases', () =>
    assert.ok(/\$\{repo_root\}\/deployment\/aliases/.test(registry))
  );
  check('omits dev-only sources', () => {
    for (const dev of ['codex-sessions', 'compute-env-local', 'git-history', 'openspec']) {
      assert.ok(!new RegExp(`^\\s+${dev}:`, 'm').test(registry), `dev-only source ${dev} leaked into shipped registry`);
    }
  });
  check('ships working-slides / working-paper / working-markdown / analysis-artifacts', () => {
    for (const src of ['working-slides', 'working-paper', 'working-markdown', 'analysis-artifacts']) {
      assert.ok(new RegExp(`^\\s+${src}:`, 'm').test(registry), `expected ${src} in shipped registry`);
    }
  });
  check('working-* sources reach working/slides, working/paper, working dirs', () => {
    assert.ok(/\$\{repo_root\}\/working\/slides/.test(registry));
    assert.ok(/\$\{repo_root\}\/working\/paper/.test(registry));
    assert.ok(/\$\{repo_root\}\/working\n/.test(registry) || /\$\{repo_root\}\/working$/m.test(registry));
  });

  console.log('\n3. cooper engine status (no engine installed)');
  const statusR = run('node', [COOPER_BIN, 'engine', 'status'], { cwd: tmpRoot });
  check('status exits 0 (informational)', () => assert.strictEqual(statusR.status, 0));
  check('reports venv MISSING', () => assert.match(statusR.stdout, /venv\s+:\s+MISSING/));
  check('reports env file MISSING', () => assert.match(statusR.stdout, /env file\s+:\s+MISSING/));
  check('reports engine cli MISSING', () => assert.match(statusR.stdout, /engine cli\s+:\s+MISSING/));

  console.log('\n4. cooper ingest (no engine installed)');
  const ingestR = run('node', [COOPER_BIN, 'ingest'], { cwd: tmpRoot });
  check('ingest exits 1', () => assert.strictEqual(ingestR.status, 1));
  check('hint mentions cooper engine install', () =>
    assert.match(ingestR.stderr, /cooper engine install/)
  );
  check('no Python stack trace', () => assert.ok(!/Traceback/.test(ingestR.stderr)));

  console.log('\n5. drift check');
  const driftR = run('node', [path.join(REPO_ROOT, 'scripts', 'check-deployment-template.js')]);
  check('drift checker exits 0', () => assert.strictEqual(driftR.status, 0, driftR.stderr));

  fs.rmSync(tmpRoot, { recursive: true, force: true });

  console.log(`\n${passed + failed} checks: ${passed} passed, ${failed} failed`);
  if (failed > 0) process.exit(1);
}

if (require.main === module) {
  main();
}

